14	function isNeighbor([x, y]: Cell, [ox, oy]: Cell): boolean {
15	  const dx = Math.abs(ox - x);
16	  const dy = Math.abs(oy - y);
17	  const isWithinRange = dx <= 1 && dy <= 1;
18	  const isSameCell = dx === 0 && dy === 0;
19	  return isWithinRange && !isSameCell;
20	}
